async function loadUsersFromSupabase() {
  try {
    const { data, error } = await supabase.from("usuarios").select("*");
    if (error) throw error;
    return data || [];
  } catch (e) {
    console.warn("Supabase users load failed, using localStorage:", e);
    try { const r = localStorage.getItem(USERS_KEY); if (r) return JSON.parse(r); } catch {}
    return [];
  }
}
async function saveUserToSupabase(user) {
  try {
    const { error } = await supabase.from("usuarios").upsert({
      id: user.email,
      email: user.email,
      password: user.password,
      name: user.name,
      role: user.role,
    }, { onConflict: "email" });
    if (error) throw error;
    return true;
  } catch (e) {
    console.warn("Supabase user save failed:", e);
    return false;
  }
}
async function deleteUserFromSupabase(email) {
  try {
    const { error } = await supabase.from("usuarios").delete().eq("email", email);
    if (error) throw error;
    return true;
  } catch (e) {
    console.warn("Supabase user delete failed:", e);
    return false;
  }
}
